diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..07aa7846cdd0 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3150,6 +3150,60 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     }
   }

+  // select(select(X, Y, false), Z, select(X, A, B)) -> select(X, select(Y, Z, A), B)
+  // select(select(X, true, Y), Z, select(X, A, B)) -> select(X, Z, select(Y, Z, B))
+  if (auto *CondSI = dyn_cast<SelectInst>(CondVal)) {
+    Value *X = CondSI->getCondition();
+    Value *CondTrue = CondSI->getTrueValue();
+    Value *CondFalse = CondSI->getFalseValue();
+    // Check for condition-select where one arm is a constant bool.
+    if (CondSI->hasOneUse() &&
+        CondTrue->getType() == CondSI->getType() &&
+        (match(CondFalse, m_Zero()) || match(CondTrue, m_One()))) {
+      if (auto *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
+        if (FalseSI->getCondition() == X) {
+          if (match(CondFalse, m_Zero())) {
+            // select(select X, Y, false), Z, (select X, A, B)
+            //   -> select X, (select Y, Z, A), B
+            Value *Y = CondTrue;
+            Value *A = FalseSI->getTrueValue();
+            Value *B = FalseSI->getFalseValue();
+            Value *Sel = Builder.CreateSelect(Y, TrueVal, A);
+            return SelectInst::Create(X, Sel, B);
+          }
+          if (match(CondTrue, m_One())) {
+            // select(select X, true, Y), Z, (select X, A, B)
+            //   -> select X, Z, (select Y, Z, B)
+            Value *Y = CondFalse;
+            Value *B = FalseSI->getFalseValue();
+            Value *Sel = Builder.CreateSelect(Y, TrueVal, B);
+            return SelectInst::Create(X, TrueVal, Sel);
+          }
+        }
+      }
+      if (auto *TrueSI = dyn_cast<SelectInst>(TrueVal)) {
+        if (TrueSI->getCondition() == X) {
+          if (match(CondFalse, m_Zero())) {
+            // select(select X, Y, false), (select X, A, B), Z
+            //   -> select X, (select Y, A, Z), Z
+            Value *Y = CondTrue;
+            Value *A = TrueSI->getTrueValue();
+            Value *Sel = Builder.CreateSelect(Y, A, FalseVal);
+            return SelectInst::Create(X, Sel, FalseVal);
+          }
+          if (match(CondTrue, m_One())) {
+            // select(select X, true, Y), (select X, A, B), Z
+            //   -> select X, A, (select Y, B, Z)
+            Value *Y = CondFalse;
+            Value *B = TrueSI->getFalseValue();
+            Value *Sel = Builder.CreateSelect(Y, B, FalseVal);
+            return SelectInst::Create(X, TrueVal, Sel);
+          }
+        }
+      }
+    }
+  }
